// Extrair dados da requisição Vapi
const input = $input.item.json;

// Vapi envia dados em body.message.toolCalls[0].function.arguments
let body;
if (input.body?.message?.toolCalls?.[0]?.function?.arguments) {
  body = input.body.message.toolCalls[0].function.arguments;
} else if (input.body) {
  // Fallback para formato direto
  body = input.body;
} else {
  body = input;
}

// Validação de entrada
if (!body.date) {
  throw new Error('Parâmetro "date" é obrigatório');
}

// Parse da data e aplicar timezone Açores (Atlantic/Azores)
let targetDate;
try {
  // Aceitar formato YYYY-MM-DD ou ISO
  if (body.date.includes('T')) {
    targetDate = new Date(body.date);
  } else {
    // Adicionar timezone dos Açores
    targetDate = new Date(body.date + 'T00:00:00-01:00');
  }

  if (isNaN(targetDate.getTime())) {
    throw new Error('Formato de data inválido');
  }
} catch (e) {
  throw new Error('Formato de data inválido. Use YYYY-MM-DD');
}

// Formatar para ISO com timezone dos Açores
const dateStr = body.date.includes('T') ? body.date.split('T')[0] : body.date;

return {
  date: dateStr,
  timezone: 'Atlantic/Azores',
  service_type: body.service_type || '',
  original_request: body
};

