// Define horário de trabalho (9h-18h) - timezone Açores
const workStart = 9;
const workEnd = 18;
const slotDuration = 60; // minutos

// Obter eventos do calendário (pode estar vazio)
const events = $input.all();

// Get date from previous node
const targetDate = $node['Extract Parameters'].json.date;
const timezone = 'Atlantic/Azores';

// Gerar todos os slots possíveis do dia
const allSlots = [];
for (let hour = workStart; hour < workEnd; hour++) {
  allSlots.push({
    time: `${hour.toString().padStart(2, '0')}:00`,
    duration: slotDuration
  });
}

// Filtrar slots ocupados
const availableSlots = allSlots.filter(slot => {
  const slotStart = new Date(`${targetDate}T${slot.time}:00-01:00`);
  const slotEnd = new Date(slotStart.getTime() + slotDuration * 60000);

  // Verificar se slot conflita com algum evento existente
  return !events.some(event => {
    if (!event.json.start || !event.json.end) return false;

    const eventStart = new Date(event.json.start.dateTime || event.json.start.date);
    const eventEnd = new Date(event.json.end.dateTime || event.json.end.date);

    return (slotStart < eventEnd && slotEnd > eventStart);
  });
});

return {
  available: availableSlots.length > 0,
  date: targetDate,
  timezone: timezone,
  available_slots: availableSlots,
  total_slots: availableSlots.length,
  message: availableSlots.length > 0 
    ? `Temos ${availableSlots.length} horário${availableSlots.length > 1 ? 's' : ''} disponível${availableSlots.length > 1 ? 'eis' : ''} para esse dia`
    : `Não há horários disponíveis para esse dia. Por favor, escolha outra data.`
};
